void OnKeyDown(UINT nChar)

{

	// Add your keyboard handler code here

   Group.Sound_Holder.Stop(0);

   SetTimer(0);



      // Odgrywane jest demo - nic nie mozna robic na klawiaturze

   if( akcja == 3 )

      return;



   if( nChar==keyDown ) return;

   keyDown = nChar;



   switch(nChar)

   {                

      case 109: // q - skrzypce 0 

      case 77:

         Muzyka( 0, 1 );

         break;



      case 44: // w - skrzypce 1

         Muzyka( 1, 1 );

         break;    



      case 46:  // e - skrzypce 2

         Muzyka( 2, 1 );

         break;                                              



      case 47: // r - skrzypce 3

         Muzyka( 3, 1 );

         break;



      case 107: // t - skrzypce 4

      case 75:

         Muzyka( 4, 1 );

         break;



      case 108: // y - skrzypce 5

      case 76:

         Muzyka( 5, 1 );

         break;



      case 59: // u - skrzypce 6

         Muzyka( 6, 1 );

         break;



      case 39: // i - skrzypce 7

         Muzyka( 7, 1 );

         break;



      case 120:  // tab - tupniecie

      case 88:

         Muzyka( 8, 1 );

         break;



      case 122: // spacja - instrument

      case 90:

         Muzyka( 9, 1 );

         break;



      case 97: // o - gwizd

      case 65:

         Muzyka( 10, 1 );

         break;



      case 115: // p - gwizd

      case 83:

         Muzyka( 11, 1 );

         break;

   }

}







void OnKeyUp(UINT nChar)

{

        //Add your command handler code here

   keyDown = 0;

}



///////////////////////////////////////////////////////////////////////

//   nrRuchu - wskazuje ktory ruch bedzie wykonany

//      

//

// 0 - skrzypce1  - sound 0 

// 1 - skrzypce2  - sound 1

// 2 - skrzypce3  - sound 2

// 3 - skrzypce4  - sound 3

// 4 - skrzypce1  - sound 4 

// 5 - skrzypce2  - sound 5

// 6 - skrzypce3  - sound 6

// 7 - skrzypce4  - sound 7

// 8 - but        - sound 8, 9, 10

// 9 - instrument - sound 11

// 10 - gwizd     - sound 12

// 11 - ryk       - sound 13

// 

void Muzyka( int nrRuchu, int dzwiek )

{

      // Jelis dzwiek dotyczy skrzypiec to 

      // - nalezy ruszyc smyczkiem w przeciwym kierunku

   if( nrRuchu < 8 )

   {

      Sound_Holder.PlayDSound( nrRuchu );

      if( dzwiek == 0 )

         Sound_Holder.SetPlayDSoundParameters( nrRuchu, -10000, 0, 0 );





      Bitmap_Holder.HideBitmap(8);



      if( smyczek )

      {

            // smyczek z prawej

         Bitmap_Holder.HideBitmap(0);

         smyczek = 0;

      }

      else

      {

         smyczek = 1;

         Bitmap_Holder.ShowBitmap(0);

      }

   }





   switch( nrRuchu )

   {

      case 0:   // skrzypce

      case 1:

      case 2:

      case 3:

      case 4:

      case 5:

      case 6:

         Bitmap_Holder.ShowBitmap( nrRuchu+1 );



         if( (biezaceSkrzypce>-1) && (biezaceSkrzypce!=nrRuchu) )

            Bitmap_Holder.HideBitmap(biezaceSkrzypce+1);



         biezaceSkrzypce = nrRuchu;

         break;



      case 7:

         Bitmap_Holder.HideBitmap(biezaceSkrzypce+1);

         break;



      case 8:   // tupniecie

         Bitmap_Holder.HideBitmap(0);

         smyczek = 0;



         Sprite_Holder.ChangePhase( 2, 1 );

         int tupniecie = Random(8,10);

         Sound_Holder.PlayDSound( tupniecie );

         if( dzwiek == 0 )

            Sound_Holder.SetPlayDSoundParameters( tupniecie, -10000, 0, 0 );

         break;



      case 9:

         Bitmap_Holder.HideBitmap(8);

         Bitmap_Holder.HideBitmap(0);

         smyczek = 0;



         Bitmap_Holder.HideBitmap(biezaceSkrzypce+1);

         Sprite_Holder.ChangePhase( 0, 1 );

         Sprite_Holder.ChangePhase( 1, 1 );

         Sound_Holder.PlayDSound( 11 );

         if( dzwiek == 0 )

            Sound_Holder.SetPlayDSoundParameters( 11, -10000, 0, 0 );

         break;



      case 10:   // gwizd

         Bitmap_Holder.HideBitmap(biezaceSkrzypce+1);

         Bitmap_Holder.HideBitmap( 9 );   // jak gwizd to nie ryk

         Sprite_Holder.ChangePhase( 0, 0 );

         Bitmap_Holder.ShowBitmap( 8 );

         Sound_Holder.PlayDSound( 12 );

         if( dzwiek == 0 )

            Sound_Holder.SetPlayDSoundParameters( 12, -10000, 0, 0 );

         break;



      case 11:   // ryk

         Bitmap_Holder.HideBitmap( 8 ); // jak ryk to nie gwizd

         Bitmap_Holder.ShowBitmap( 9 );

         Sound_Holder.PlayDSound( 13 );

         if( dzwiek == 0 )

            Sound_Holder.SetPlayDSoundParameters( 13, -10000, 0, 0 );

         break;

   }

}







