void Sound_Holder.EndPlaySound(int soundID)

{

   switch( soundID )

   {

      case 8:

      case 9:

      case 10:

         Sprite_Holder.ChangePhase( 2, 0 );

         break;



      case 11:

         Sprite_Holder.ChangePhase( 0, 0 );

         Sprite_Holder.ChangePhase( 1, 0 );

         break



      case 12:

         Bitmap_Holder.HideBitmap(8);

         break;



      case 13:

         Bitmap_Holder.HideBitmap(9);

         break;



      default:

         break;

   }

}





