void Group.HotSpot_Holder.MouseMoveIn(int rectID)

{

   if(rectID==0)

   {

      if(toolbar)   return;

      Group.Sprite_Holder.DisableTimers();



      Group.Sprite_Holder.GotoXY(6,480,0);

      Group.Sprite_Holder.GotoXY(7,560,329);

      Group.Sprite_Holder.GotoXY(8,557,404);

      Group.Sprite_Holder.GotoXY(9,544,14);

      Group.Sprite_Holder.GotoXY(10,584,14);



      Group.Sprite_Holder.SynchronizeTimers();

      Group.Sprite_Holder.EnableTimers();

      Group.Sound_Holder.PlayDSound(2);

      SetCursor(0);

   }

   else

   {

      if(toolbar)

      {

         Group.Sprite_Holder.DisableTimers();



         Group.Sprite_Holder.GotoXY(6,640,0);

         Group.Sprite_Holder.GotoXY(7,721,329);

         Group.Sprite_Holder.GotoXY(8,717,404);

         Group.Sprite_Holder.GotoXY(9,704,14);

         Group.Sprite_Holder.GotoXY(10,744,14);



         Group.Sprite_Holder.SynchronizeTimers();

         Group.Sprite_Holder.EnableTimers();

         Group.Sound_Holder.PlayDSound(2);

         toolbar=0;

      }

      Group.HotSpot_Holder.DisableHotSpot(1);

      toolbarCase=0;

   }

}



void Group.Sprite_Holder.InPlace(int spriteID,int x,int y)

{

   if(spriteID==6)

   {

      if(x==480)

      {

         toolbar=1;

         Group.HotSpot_Holder.EnableHotSpot(1);

         SetCursor(0);

      }

      else

      {

         SetCursor(0);

         Group.Sprite_Holder.ChangePhase(7,0);

         Group.Sprite_Holder.ChangePhase(8,0);

         Group.Sprite_Holder.ChangePhase(9,0);

         Group.Sprite_Holder.ChangePhase(10,0);

         switch(toolbarCase)

         {

            case 9:	//lewo

               LoadPage("cuda_ps1.bdf");

               break;

            case 10:	//prawo

               LoadPage("zosia_ps.bdf");

               break;

            case 7:   //do planszy glownej   

               LoadPage( "taniec.bdf" );

               break;

            case 8:   //Plansza wyboru

               LoadPage("Wyborw.bdf");

               break;

         }

      }

   }

